import sharp from 'sharp'

// Pre-rendered 'AG FILMS' tile — raw RGBA pixels 300×65×4 (no PNG codec needed).
const TILE_RAW_B64 = ''
const TILE_W = 300
const TILE_H = 65

export async function applyWatermark(inputBuffer: Buffer): Promise<Buffer> {
  // Auto-rotate based on EXIF orientation (critical for phone photos)
  const oriented = await sharp(inputBuffer).rotate().toBuffer()
  const meta = await sharp(oriented).metadata()
  const origW = meta.width ?? 1200
  const origH = meta.height ?? 1500

  // Scale tile proportionally: target 25% of image width, minimum 200px
  const tileTargetW = Math.max(200, Math.round(origW * 0.25))
  const tileTargetH = Math.round(TILE_H * tileTargetW / TILE_W)

  const rawPixels = Buffer.from(TILE_RAW_B64, 'base64')
  const rotatedTile = await sharp(rawPixels, { raw: { width: TILE_W, height: TILE_H, channels: 4 } })
    .resize(tileTargetW, tileTargetH)
    .rotate(-30, { background: { r: 0, g: 0, b: 0, alpha: 0 } })
    .png()
    .toBuffer()

  const { width: tW = tileTargetW + 50, height: tH = tileTargetH + 50 } = await sharp(rotatedTile).metadata()

  const STEP_X = Math.round(tileTargetW * 0.87)
  const STEP_Y = Math.round(tileTargetH * 2.0)

  const tiles: sharp.OverlayOptions[] = []
  for (let row = 0; row * STEP_Y < origH + tH; row++) {
    const stagger = row % 2 === 1 ? Math.round(STEP_X / 2) : 0
    for (let col = 0; col * STEP_X < origW + tW; col++) {
      const left = col * STEP_X + stagger
      const top = row * STEP_Y
      if (left < origW && top < origH) {
        tiles.push({ input: rotatedTile, left, top, blend: 'over' })
      }
    }
  }

  // Composite directly on full-resolution original — no downscale
  return sharp(oriented)
    .composite(tiles)
    .jpeg({ quality: 90 })
    .toBuffer()
}